const raw = $json.text || '';

const clean = raw
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

let parsed;

try {
  parsed = JSON.parse(clean);
} catch (error) {
  parsed = {
    empresa_nome: null,
    empresa_origem: null,
    handle_extraido: null,
    confianca: 'baixa',
    motivo: 'Falha ao converter resposta do LLM em JSON'
  };
}

return {
  json: {
    empresa_nome: parsed.empresa_nome ?? null,
    empresa_origem: parsed.empresa_origem ?? null,
    handle_extraido: parsed.handle_extraido ?? null,
    confianca: parsed.confianca ?? null,
    motivo: parsed.motivo ?? null,
    empresa_json: $('Execute a SQL query').item.json
  }
};
